blocks.body:
{
    "level": "B1–B2",
    "intro": "]W tym temacie poznasz <strong>zaawansowane struktury</strong> dotyczące akcentowania: inwersja z przysłówkami przeczącymi, zdania rozszczepione i zdania z naciskiem zrobić.",
    "rules": [
        {
            "label": "Inwersja",
            "color": "emerald",
            "text": "Przysłówek przeczący + <strong>Pomocniczy + Temat</strong>:",
            "example": "]Nigdy nie widziałem takiego piękna."
        },
        {
            "label": "To-rozszczepienie",
            "color": "blue",
            "text": "<strong>To było/jest... kto/że</strong> — element wzmacniający:",
            "example": "To ty mnie zaprosiłeś."
        },
        {
            "label": "Co-rozszczep",
            "color": "amber",
            "text": "<strong>Co... jest/było</strong> — wzmocnienie działania:",
            "example": "Potrzebuję trochę reszta."
        }
    ]
}

{
    "title": "1. Kiedy używać wyróżnień",
    "intro": "Struktury emfatyczne służą do:",
    "items": [
        {
            "label": "1",
            "title": "Podkreślania informacji",
            "subtitle": "Podkreślania kto, co, kiedy, gdzie."
        },
        {
            "label": "2",
            "title": "Styl formalny",
            "subtitle": "W języku pisanym, formalnym."
        },
        {
            "label": "3",
            "title": "Kontrast",
            "subtitle": "Kontrast lub korekta."
        }
    ]
}

{
    "title": "2. Inwersja z przysłówkami przeczącymi",
    "sections": [
        {
            "label": "Struktura inwersji",
            "color": "emerald",
            "description": "Kiedy zdanie zaczyna się od <strong>przysłówka przeczącego</strong>, zmienia się kolejność słów: <strong>Pomocniczy + Temat</strong>.",
            "examples": [
                {
                    "en": "Nigdy nie widziałem tak pięknego zachód słońca.",
                    "ua": "Nigdy nie widziałem tak pięknego zachodu słońca. widziała taki zachód słońca."
                },
                {
                    "en": "Rzadko popełnia błędy.",
                    "ua": "Rzadko się myli."
                },
                {
                    "en": "Rzadko mamy takie możliwości.",
                    "ua": "Rzadko mamy takie możliwości."
                }
            ]
        },
        {
            "label": "Nie tylko… ale także",
            "color": "sky",
            "description": "Po <strong>Nie tylko</strong> odwróceniu pierwszego części.",
            "examples": [
                {
                    "en": "Nie tylko skończył wcześniej, ale także pomógł innym.",
                    "ua": "Nie tylko skończył wcześniej, ale także pomógł innym."
                },
                {
                    "en": "Nie tylko jest mądra, ale także miła.",
                    "ua": "Jest nie tylko mądra, ale także rodzaj."
                }
            ]
        },
        {
            "label": "Prawie / Nie wcześniej",
            "color": "amber",
            "description": "Zaledwie dotarliśmy na miejsce, gdy zaczęło padać.",
            "examples": [
                {
                    "en": "Hardly had we arrived when it started raining.",
                    "ua": "Zaledwie dotarliśmy, gdy zaczęło padać."
                },
                {
                    "en": "Zaledwie usiadłem, a telefon zadzwonił.",
                    "ua": "Właśnie usiadłem, kiedy zadzwonił telefon."
                }
            ],
            "note": "Prawie/Prawie + kiedy; Nie wcześniej niż."
        }
    ]
}

{
    "title": "3. Rozszczepione zdanie",
    "sections": [
        {
            "label": "Wzmocnienie osoby (kto)",
            "color": "emerald",
            "description": "Struktura <strong>To była/jest + osoba + kto</strong> wzmacnia, kto wykonał czynność.",
            "examples": [
                {
                    "en": "Zaprosiłeś mnie. → To ty mnie zaprosiłeś.",
                    "ua": "To ty mnie zaprosiłeś."
                },
                {
                    "en": "Rozbiła wazon. → To ona stłukła wazon.",
                    "ua": "To ona stłukła wazon."
                },
                {
                    "en": "John zadzwonił. To John zadzwonił. → To było wczoraj, kiedy odeszła.",
                    "ua": "Саме Джон телефонував."
                }
            ]
        },
        {
            "label": "Підсилення часу/місця/об'єкта (that)",
            "color": "sky",
            "description": "Структура <strong>It was/is + element + that</strong> для підсилення не-осіб.",
            "examples": [
                {
                    "en": "She left yesterday. → It was yesterday that she left.",
                    "ua": "To było wczoraj, kiedy odeszła."
                },
                {
                    "en": "Potrzebuję pomocy. → To pomoc, której potrzebuję.",
                    "ua": "To pomoc, której potrzebuję."
                },
                {
                    "en": "Poznaliśmy się w Paryżu. → Spotkaliśmy się w Paryżu.",
                    "ua": "Poznaliśmy się w Paryżu."
                }
            ],
            "note": "Dla ludzi – dla których w ogóle – to."
        }
    ]
}

{
    "title": "4. Jakie zdanie (pseudo-rozszczep)",
    "sections": [
        {
            "label": "Jaka-rozszczepiona struktura",
            "color": "emerald",
            "description": "<strong>Co + zdanie + jest/było + element podkreślony</strong> — wzmacnia akcję lub przedmiot.",
            "examples": [
                {
                    "en": "Potrzebuję odpoczynku. → Potrzebuję trochę odpoczynku.",
                    "ua": "Potrzebuję trochę odpoczynku."
                },
                {
                    "en": "Lubię ten park. → Podoba mi się park.",
                    "ua": "Lubię park."
                },
                {
                    "en": "Ona chce wakacje. → Ona chce wakacji.",
                    "ua": "Chce wakacji."
                }
            ]
        },
        {
            "label": "Inne konstrukcje z rozszczepem Wh",
            "color": "sky",
            "description": "Możesz użyć <strong>Gdzie, Dlaczego, Kto, Jak</strong> do różnych rodzajów zbrojenia.",
            "examples": [
                {
                    "en": "Tam, gdzie dorastałem, jest bardzo daleko od tutaj.",
                    "ua": "Miejsce, w którym dorastałem, jest bardzo daleko stąd."
                },
                {
                    "en": "Dlaczego odeszła, wciąż pozostaje tajemnicą.",
                    "ua": "Dlaczego odeszła, wciąż pozostaje tajemnicą."
                },
                {
                    "en": "Jak to zrobił, zdumiało wszystkich.",
                    "ua": "Jak to zrobił, zaskoczył wszyscy."
                }
            ]
        }
    ]
}

{
    "title": "5. Fronting i Emphatic do",
    "sections": [
        {
            "label": "Frontowanie",
            "color": "emerald",
            "description": "<strong>Frontowanie</strong> — umieszczanie elementu na początku zdania dla podkreślenia lub kontrastu.",
            "examples": [
                {
                    "en": "Dzieci szybko wyszły. → Szybko dzieci wyszły.",
                    "ua": "Szybko dzieci wyszły."
                },
                {
                    "en": "Bardzo podoba mi się ta książka. → Ta książka bardzo mi się podoba.",
                    "ua": "Ta książka bardzo mi się podoba."
                },
                {
                    "en": "Away run the kids.",
                    "ua": "Away run the kids."
                }
            ],
            "note": "Często używane w literaturze i formalnym języku angielskim."
        },
        {
            "label": "Zdecydowany do/does/did",
            "color": "sky",
            "description": "W przypadku podkreślenia w zdaniach <strong>twierdzających</strong> użyj robić/robi/robił z naciskiem.",
            "examples": [
                {
                    "en": "Podoba mi się. → NAPRAWDĘ mi się to podoba!",
                    "ua": "Naprawdę mi się podoba!"
                },
                {
                    "en": "Skończyła. → ONA odrobiła pracę domową!",
                    "ua": "Odrobiła pracę domową!"
                },
                {
                    "en": "On wie. → ON zna odpowiedź.",
                    "ua": "On naprawdę zna odpowiedź."
                }
            ],
            "note": "Często używane potocznie w celu potwierdzenia."
        }
    ]
}

{
    "title": "6. Przysłówki przeczące oznaczające inwersję",
    "intro": "Zapamiętaj te wyrażenia – po nich musi nastąpić inwersja:",
    "rows": [
        {
            "en": "Nigdy",
            "ua": "nigdy",
            "note": "Nigdy nie miałem..."
        },
        {
            "en": "Rzadko / Rzadko",
            "ua": "rzadko",
            "note": "Rzadko ona..."
        },
        {
            "en": "Prawie/rzadko",
            "ua": "ledwie",
            "note": "Prawie nie miała my..."
        },
        {
            "en": "Nie tylko",
            "ua": "nie tylko",
            "note": "Nie tylko on..."
        },
        {
            "en": "Nie wcześniej",
            "ua": "tylko",
            "note": "Nie wcześniej Ja..."
        },
        {
            "en": "Tylko kiedy/po/jeśli[[[CODX_30]]]tylko kiedy/po/jeśli[[[CODX_SEG_31]]Tylko] kiedy przybyłem...",
            "ua": "тільки коли/після/якщо",
            "note": "Only when I arrived did I..."
        }
    ],
    "warning": "📌 Jeśli nie ma czasownika posiłkowego - dodaj zrobić/robi/zrobił."
}

{
    "title": "7. Typowe błędy osób mówiących po ukraińsku",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Brakująca inwersja po przysłówku przeczącym.",
            "wrong": "Nigdy nie widziałem...",
            "right": " ✅ <span class="font-mono">Nigdy nie widziałem...</span>[[[CODX_3]]]Błąd 2"
        },
        {
            "label": "Помилка 2",
            "color": "amber",
            "title": "Który zamiast tego z jakich osób.",
            "wrong": "To ty mnie zaprosiłeś.[[[CODX_6]]]​​​​ <span class="font-mono">To ty mnie zaprosiłeś.</span>",
            "right": "✅ <span class="font-mono">It was you who invited me.</span>"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Bezokolicznik zamiast rzeczownika w Co za rozłam.[[[CODX_9]]]Potrzebuję odpoczynku.",
            "wrong": "What I need is to rest.",
            "right": "​​​​​​​​​​ odpowiedź.</span>[[CODX_SEG_15]]]8. Krótkie streszczenie"
        },
        {
            "label": "Помилка 4",
            "color": "purple",
            "title": "Дієслово з -s після emphatic do.",
            "wrong": "He do knows the answer.",
            "right": "✅ <span class="font-mono">He does know the answer.</span>"
        }
    ]
}

{
    "title": "9. Ćwicz",
    "select_title": "Ćwiczenie 1. Wybierz właściwą opcję",
    "select_intro": "Wybierz zdania o prawidłowej strukturze.",
    "selects": [
        {
            "label": "a) Nigdy nie widziałem... / b) Nigdy nie widziałem...",
            "prompt": "Która opcja to prawda?"
        },
        {
            "label": "a) To ty mnie zaprosiłeś. / b) To ty mnie zaprosiłeś.",
            "prompt": "Która opcja jest poprawna?"
        },
        {
            "label": "a) Potrzebuję trochę odpoczynku. / b) Potrzebowałem odpoczynku. →",
            "prompt": "Який варіант правильний?"
        }
    ],
    "options": [
        "a",
        "b"
    ],
    "input_title": "Вправа 2. Перетвори на It-cleft",
    "input_intro": "Підсиль виділений елемент за допомогою It-cleft.",
    "inputs": [
        {
            "before": "YOU called me. →",
            "after": "To było..."
        },
        {
            "before": "Wyjechała WCZORAJ. →",
            "after": "To było..."
        },
        {
            "before": "Potrzebuję POMOCY. To jest... piękno.",
            "after": "It is..."
        }
    ],
    "rephrase_title": "Вправа 3. Додай інверсію",
    "rephrase_intro": "Перетвори речення, починаючи з негативного прислівника.",
    "rephrase": [
        {
            "example_label": "Приклад:",
            "example_original": "I have never seen such beauty.",
            "example_target": "Never have I seen such beauty."
        },
        {
            "original": "1. Rzadko popełnia błędy.",
            "placeholder": "Rzadko..."
        },
        {
            "original": "2. Nie tylko skończył wcześniej, ale także pomógł. Przysłówki i okoliczności",
            "placeholder": "Not only..."
        }
    ]
}

{
    "title": "Інші сторінки з базової граматики",
    "items": [
        {
            "label": "Basic Word Order — Порядок слів у ствердженні",
            "current": false
        },
        {
            "label": "Word Order in Questions and Negatives — Питання та заперечення",
            "current": false
        },
        {
            "label": "Word Order with Adverbs — Прислівники та обставини",
            "current": false
        },
        {
            "label": "Kolejność wyrazów z czasownikami i dopełnieniami – czasowniki i załączniki",
            "current": false
        },
        {
            "label": "Zaawansowany szyk wyrazów – inwersja i wzmocnienie (bieżące)",
            "current": true
        }
    ]
}
